// BenchmarkRunner.cs
public sealed class BenchmarkRunner : IBenchmarkRunner, IAsyncDisposable
{
    private readonly SemaphoreSlim _modelServerLock = new(1, 1);
    private readonly ConcurrentDictionary<Guid, BenchmarkJob> _jobs = new();
    private readonly ILogger<BenchmarkRunner> _logger;
    private readonly DockerHarness _harness;
    private readonly CancellationTokenSource _cts = new();

    public BenchmarkRunner(DockerHarness harness, ILogger<BenchmarkRunner> logger)
    {
        _harness = harness;
        _logger = logger;
    }

    public async Task<Guid> RunAsync(BenchmarkContext context, CancellationToken ct = default)
    {
        var id = Guid.NewGuid();
        var job = new BenchmarkJob(id, context);
        _jobs.TryAdd(id, job);

        try
        {
            await _modelServerLock.WaitAsync(ct);
            try
            {
                job.Status = JobStatus.Running;
                _logger.LogInformation("Starting benchmark {Id} for {Model}", id, context.Model);

                var results = await _harness.RunAsync(context, ct);
                job.Result = results;
                job.Status = JobStatus.Completed;
                job.Score = context.Score(results);
            }
            finally
            {
                _modelServerLock.Release();
            }
        }
        catch (OperationCanceledException) when (!ct.IsCancellationRequested && _cts.IsCancellationRequested)
        {
            job.Status = JobStatus.Cancelled;
            throw;
        }
        catch (Exception ex)
        {
            job.Status = JobStatus.Failed;
            job.Error = ex.Message;
            _logger.LogError(ex, "Benchmark {Id} failed", id);
        }

        return id;
    }

